import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentGrade {
  subject: string;
  grade: string;
}

interface SubjectPerformance {
  subject: string;
  score: number;
}

interface GradeTrackerData {
  currentGPA: number;
  recentGrades: RecentGrade[];
  subjectPerformance: SubjectPerformance[];
}

export default function Widget() {
  const data = response.data as GradeTrackerData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#3B82F6' }}>
              Current GPA
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {data.currentGPA.toFixed(2)}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Recent Grades
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {data.recentGrades.map((grade, index) => (
                <Typography key={index} variant="body2" color="text.primary" sx={{ fontWeight: 500 }}>
                  {grade.subject}: {grade.grade}
                </Typography>
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <BarChart
              height={140}
              series={[
                {
                  data: data.subjectPerformance.map((sp) => sp.score),
                  color: '#F59E0B',
                },
              ]}
              xAxis={[
                {
                  data: data.subjectPerformance.map((sp) => sp.subject),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
